using System;
using System.Collections;
using System.Collections.Generic;
using System.Text;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Formas" do Menu de Pausa (Tarefa #9) — a árvore das transformações.
///
/// No centro, uma grande árvore onde cada mundo ocupa um ramo
/// (<see cref="branches"/>). Em cada ramo, cada <see cref="AnimalFormData"/>
/// cujo <see cref="AnimalFormData.originWorld"/> seja esse mundo aparece como:
/// - constelação/gravação/espírito luminoso (<see cref="AnimalFormData.constellationIcon"/>,
///   ou "icon" se vazio) — se já libertado (<see cref="PlayerProgress.HasFreedAnimal"/>);
/// - silhueta (<see cref="AnimalFormData.silhouette"/>), semi-transparente e não
///   seleccionável — se ainda não libertado e NÃO for
///   <see cref="AnimalFormData.isSecretForm"/>;
/// - nada — se ainda não libertado e for "isSecretForm" (animais secretos só
///   passam a existir como ramo depois de desbloqueados).
///
/// Ao seleccionar um animal libertado, mostra a sua ficha (centro):
/// nome, categorias (com ícones via <see cref="categoryIcons"/>), "Habilidade
/// natural", "Instinto", "Boa para", "Fraqueza", "Libertada em" — e, ao lado,
/// uma pequena animação idle (<see cref="AnimalFormData.menuIdleController"/>).
///
/// Quando uma nova forma é desbloqueada, outro sistema pode chamar
/// <see cref="PlayUnlockReveal"/> (ex: Action_RevealAnimalForm) para abrir esta
/// secção e tocar uma pequena animação de revelação no ramo correspondente.
///
/// Montagem no Editor:
/// - "branches": um por mundo (Bosque de Bruma, Planícies do Sol Alto, Verde
///   Infinito, Terras da Aurora, Eucalipto e Coral, Bambu e Lanternas, ...),
///   cada um com o "container" (Transform) onde os nós desse ramo são gerados.
/// - "allForms": todas as AnimalFormData do jogo (qualquer ordem — cada uma vai
///   para o ramo do seu "originWorld").
/// - "formNodePrefab": prefab com <see cref="FormNodeUI"/> (Image + Selectable
///   opcional, para animais libertados poderem ser navegados/seleccionados).
/// </summary>
public class FormsSectionUI : MonoBehaviour, IPauseMenuSection
{
    /// <summary>
    /// Referência para outros sistemas (ex: Action_RevealAnimalForm) chamarem
    /// <see cref="PlayUnlockReveal"/> quando uma forma é desbloqueada.
    /// </summary>
    public static FormsSectionUI Instance { get; private set; }

    [Serializable]
    public class Branch
    {
        public WorldData world;
        public Transform container;
    }

    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Árvore das Transformações")]
    [Tooltip("Um ramo por mundo — define onde os nós de cada AnimalFormData (por 'originWorld') são gerados.")]
    [SerializeField] private List<Branch> branches = new List<Branch>();

    [Tooltip("Todas as AnimalFormData do jogo. Cada uma aparece no ramo do seu 'originWorld'.")]
    [SerializeField] private List<AnimalFormData> allForms = new List<AnimalFormData>();

    [SerializeField] private FormNodeUI formNodePrefab;

    [Header("Categorias")]
    [SerializeField] private AnimalCategoryIconSet categoryIcons;
    [SerializeField] private string categorySeparator = " • ";
    [SerializeField] private Transform categoryIconContainer;
    [SerializeField] private Image categoryIconPrefab;

    [Header("Ficha da Forma (centro)")]
    [SerializeField] private GameObject detailRoot;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private TMP_Text categoriesText;

    [SerializeField] private string naturalAbilityFormat = "Habilidade natural\n{0}";
    [SerializeField] private TMP_Text naturalAbilityText;

    [SerializeField] private string instinctFormat = "Instinto\n{0}";
    [SerializeField] private TMP_Text instinctText;

    [SerializeField] private string goodForFormat = "Boa para\n{0}";
    [SerializeField] private TMP_Text goodForText;

    [SerializeField] private string weaknessFormat = "Fraqueza\n{0}";
    [SerializeField] private TMP_Text weaknessText;

    [SerializeField] private string releasedInFormat = "Libertada em\n{0}";
    [SerializeField] private TMP_Text releasedInText;

    [Header("Animação Idle (ao lado da ficha)")]
    [SerializeField] private GameObject idleRoot;
    [SerializeField] private Animator idleAnimator;

    [Header("Estado Vazio")]
    [SerializeField] private GameObject emptyState;
    [SerializeField] private string emptyText = "Nenhuma transformação libertada ainda.";

    [Header("Revelação de Nova Forma")]
    [Tooltip("Duração do pulso de escala ao revelar uma forma nova no ramo.")]
    [SerializeField] private float revealPulseDuration = 0.6f;

    [Tooltip("Escala máxima do nó durante o pulso de revelação (1 = tamanho normal).")]
    [SerializeField] private float revealPulseScale = 1.6f;

    [SerializeField] private AudioClip revealSfx;

    private readonly Dictionary<AnimalFormData, FormNodeUI> spawnedNodes = new Dictionary<AnimalFormData, FormNodeUI>();
    private AnimalFormData selectedForm;
    private Coroutine revealRoutine;

    public string SectionName => "FORMAS";
    public GameObject Root => root != null ? root : gameObject;

    private void Awake()
    {
        if (Instance == null) Instance = this;
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    // ---------------- IPauseMenuSection ----------------

    public void Refresh()
    {
        BuildTree();

        if (selectedForm == null || !IsFreed(selectedForm))
            selectedForm = FindFirstFreedForm();

        if (selectedForm == null)
        {
            if (emptyState != null)
            {
                emptyState.SetActive(true);

                var emptyTextComponent = emptyState.GetComponentInChildren<TMP_Text>();
                if (emptyTextComponent != null) emptyTextComponent.text = emptyText;
            }

            if (detailRoot != null) detailRoot.SetActive(false);
            return;
        }

        if (emptyState != null) emptyState.SetActive(false);
        if (detailRoot != null) detailRoot.SetActive(true);

        ShowDetails(selectedForm);

        if (spawnedNodes.TryGetValue(selectedForm, out var node) && EventSystem.current != null)
            EventSystem.current.SetSelectedGameObject(node.gameObject);
    }

    public void OnHide()
    {
        // Sem estado próprio a limpar — Refresh() reconstrói o ramo na próxima vez.
    }

    // ---------------- Árvore ----------------

    private void BuildTree()
    {
        ClearTree();

        var progress = PlayerProgress.Instance;

        foreach (var form in allForms)
        {
            if (form == null) continue;

            bool freed = progress != null && progress.HasFreedAnimal(form.formId);
            if (!freed && form.isSecretForm) continue; // animais secretos: nada até serem desbloqueados.

            var branch = FindBranch(form.originWorld);
            if (branch?.container == null)
            {
                Debug.LogWarning($"[FormsSectionUI] '{form.displayName}' não tem ramo configurado para o mundo '{(form.originWorld != null ? form.originWorld.displayName : "(nenhum)")}'.");
                continue;
            }

            if (formNodePrefab == null) continue;

            var node = Instantiate(formNodePrefab, branch.container);
            node.gameObject.SetActive(true);
            node.Setup(form, freed, OnFormSelected);

            spawnedNodes[form] = node;
        }
    }

    private void ClearTree()
    {
        foreach (var node in spawnedNodes.Values)
            if (node != null) Destroy(node.gameObject);

        spawnedNodes.Clear();
    }

    private Branch FindBranch(WorldData world)
    {
        if (world == null) return null;

        foreach (var branch in branches)
            if (branch != null && branch.world == world) return branch;

        return null;
    }

    private bool IsFreed(AnimalFormData form)
    {
        var progress = PlayerProgress.Instance;
        return form != null && progress != null && progress.HasFreedAnimal(form.formId);
    }

    private AnimalFormData FindFirstFreedForm()
    {
        foreach (var form in allForms)
            if (form != null && IsFreed(form)) return form;

        return null;
    }

    // ---------------- Selecção / Ficha ----------------

    private void OnFormSelected(AnimalFormData form)
    {
        if (form == null || !IsFreed(form)) return;

        selectedForm = form;
        ShowDetails(form);
    }

    private void ShowDetails(AnimalFormData form)
    {
        if (form == null) return;

        if (nameText != null) nameText.text = form.displayName;

        if (categoriesText != null) categoriesText.text = BuildCategoriesLabel(form);
        SpawnCategoryIcons(form);

        if (naturalAbilityText != null) naturalAbilityText.text = string.Format(naturalAbilityFormat, form.naturalAbilityText);
        if (instinctText != null) instinctText.text = string.Format(instinctFormat, form.instinctText);
        if (goodForText != null) goodForText.text = string.Format(goodForFormat, form.goodForText);
        if (weaknessText != null) weaknessText.text = string.Format(weaknessFormat, form.weaknessText);

        if (releasedInText != null)
        {
            string worldName = form.originWorld != null ? form.originWorld.displayName : string.Empty;
            releasedInText.text = string.Format(releasedInFormat, worldName);
        }

        if (idleAnimator != null)
        {
            idleAnimator.runtimeAnimatorController = form.menuIdleController;
            if (idleRoot != null) idleRoot.SetActive(form.menuIdleController != null);
        }
    }

    private string BuildCategoriesLabel(AnimalFormData form)
    {
        if (categoryIcons == null) return string.Empty;

        var sb = new StringBuilder();
        bool first = true;

        foreach (var entry in categoryIcons.Match(form.categories))
        {
            if (string.IsNullOrEmpty(entry.displayName)) continue;

            if (!first) sb.Append(categorySeparator);
            sb.Append(entry.displayName);
            first = false;
        }

        return sb.ToString();
    }

    private readonly List<GameObject> spawnedCategoryIcons = new List<GameObject>();

    private void SpawnCategoryIcons(AnimalFormData form)
    {
        foreach (var go in spawnedCategoryIcons)
            if (go != null) Destroy(go);
        spawnedCategoryIcons.Clear();

        if (categoryIcons == null || categoryIconPrefab == null || categoryIconContainer == null) return;

        foreach (var entry in categoryIcons.Match(form.categories))
        {
            if (entry.icon == null) continue;

            var image = Instantiate(categoryIconPrefab, categoryIconContainer);
            image.gameObject.SetActive(true);
            image.sprite = entry.icon;
            spawnedCategoryIcons.Add(image.gameObject);
        }
    }

    // ---------------- Revelação de Nova Forma ----------------

    /// <summary>
    /// Abre o Menu de Pausa nesta secção e toca uma pequena animação de
    /// revelação (pulso de escala + som) no nó de "form" — chamado quando o
    /// jogador acaba de libertar essa transformação (Tarefa #9: "essa tela
    /// abre, e aparece a animação do animal sendo revelado no ramo").
    /// </summary>
    public void PlayUnlockReveal(AnimalFormData form)
    {
        if (PauseMenuController.Instance != null)
            PauseMenuController.Instance.OpenToSection(this);
        else
            Refresh();

        if (form == null) return;
        selectedForm = form;

        if (!spawnedNodes.ContainsKey(form)) BuildTree();
        ShowDetails(form);

        if (spawnedNodes.TryGetValue(form, out var node))
        {
            if (EventSystem.current != null) EventSystem.current.SetSelectedGameObject(node.gameObject);

            if (revealRoutine != null) StopCoroutine(revealRoutine);
            revealRoutine = StartCoroutine(RevealPulse(node));
        }

        AudioManager.Instance?.PlaySE(revealSfx);
    }

    private IEnumerator RevealPulse(FormNodeUI node)
    {
        if (node == null) yield break;

        var rect = node.transform as RectTransform;
        if (rect == null) yield break;

        float duration = Mathf.Max(0.01f, revealPulseDuration);
        float t = 0f;

        while (t < duration)
        {
            t += Time.unscaledDeltaTime;
            float p = Mathf.Clamp01(t / duration);

            // Sobe até "revealPulseScale" a meio e volta a 1 no fim (ease-out).
            float pulse = Mathf.Sin(p * Mathf.PI);
            float scale = Mathf.Lerp(1f, revealPulseScale, pulse);

            rect.localScale = Vector3.one * scale;
            yield return null;
        }

        rect.localScale = Vector3.one;
    }
}

/// <summary>
/// Nó de um animal na árvore das transformações (FormsSectionUI). Mostra a
/// constelação (animal libertado) ou a silhueta (animal ainda não libertado,
/// não-secreto). Implementa <see cref="ISelectHandler"/> para que a navegação
/// por D-pad/teclado actualize a ficha ao focar o nó — apenas animais
/// libertados são interactivos.
/// </summary>
public class FormNodeUI : MonoBehaviour, ISelectHandler
{
    [SerializeField] private Image iconImage;

    [Tooltip("Opacidade do ícone quando ainda é uma silhueta (animal não libertado).")]
    [SerializeField] private float silhouetteAlpha = 0.35f;

    private Action<AnimalFormData> onSelected;

    public AnimalFormData Form { get; private set; }
    public bool IsFreed { get; private set; }

    public void Setup(AnimalFormData form, bool freed, Action<AnimalFormData> onSelected)
    {
        Form = form;
        IsFreed = freed;
        this.onSelected = onSelected;

        if (iconImage != null)
        {
            Sprite sprite = freed
                ? (form.constellationIcon != null ? form.constellationIcon : form.icon)
                : form.silhouette;

            iconImage.sprite = sprite;
            iconImage.enabled = sprite != null;
            iconImage.color = freed ? Color.white : new Color(1f, 1f, 1f, silhouetteAlpha);
        }

        var selectable = GetComponent<Selectable>();
        if (selectable != null) selectable.interactable = freed;
    }

    public void OnSelect(BaseEventData eventData)
    {
        if (IsFreed) onSelected?.Invoke(Form);
    }
}
